CREATE TABLE orders (id SERIAL PRIMARY KEY, order_number VARCHAR(20) UNIQUE NOT NULL, user_id INTEGER REFERENCES users(id), client_name VARCHAR(100) NOT NULL, client_phone VARCHAR(20) NOT NULL, car VARCHAR(150), service VARCHAR(200) NOT NULL, date VARCHAR(20) NOT NULL, time VARCHAR(10) NOT NULL, master VARCHAR(100), status VARCHAR(20) DEFAULT 'scheduled', total INTEGER DEFAULT 0, comment TEXT, created_at TIMESTAMP DEFAULT NOW());